"use client";

import { useState } from "react";
import { X, Minus, Plus, Trash2, ShoppingCart as CartIcon, List } from "lucide-react";
import Home from "../home";

export default function CartSidebar() {
    const [isCartOpen, setIsCartOpen] = useState(true);
    const [activeTab, setActiveTab] = useState("shopcart");

    const cartItems = [
        {
            id: 1,
            name: "Be Nice Shower Cream, Perfect Elastic Formula, 450 ml.",
            price: 109,
            qty: 1,
            stock: 200,
            image: "/images/products/showercream.png",
        },
        {
            id: 2,
            name: "Protex Lavender Ice Freeze Soap Bar 60 g.",
            price: 57,
            qty: 3,
            stock: 359,
            image: "/images/products/protex.png",
        },
        {
            id: 3,
            name: "KFC BamBam BOX Menu TheBox special",
            price: 159,
            qty: 1,
            stock: 20,
            image: "/images/products/kfc.png",
        },
    ];

    return (
        <div className="relative">
            {/* หน้า Home */}
            <div className={isCartOpen ? "blur-sm" : ""}>
                <Home />
            </div>

            {/* Overlay */}
            {isCartOpen && (
                <div
                    className="fixed inset-0 bg-black/30 z-40"
                    onClick={() => setIsCartOpen(false)}
                />
            )}

            {/* Cart Sidebar */}
            <div
                className={`fixed top-0 right-0 w-96 h-full bg-white shadow-lg z-50 transform transition-transform duration-300 ${
                    isCartOpen ? "translate-x-0" : "translate-x-full"
                }`}
            >
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b">
                    {/* Tabs */}
                    <div className="flex space-x-4">
                        <button
                            onClick={() => setActiveTab("shopcart")}
                            className={`flex items-center space-x-1 ${
                                activeTab === "shopcart"
                                    ? "text-green-600 font-semibold border-b-2 border-green-600"
                                    : "text-gray-500"
                            }`}
                        >
                            <CartIcon size={18} />
                            <span>ShopCart</span>
                        </button>
                        <button
                            onClick={() => setActiveTab("order")}
                            className={`flex items-center space-x-1 ${
                                activeTab === "order"
                                    ? "text-green-600 font-semibold border-b-2 border-green-600"
                                    : "text-gray-500"
                            }`}
                        >
                            <List size={18} />
                            <span>Order</span>
                        </button>
                    </div>

                    <button onClick={() => setIsCartOpen(false)}>
                        <X size={24} />
                    </button>
                </div>

                {/* Content */}
                <div className="p-6 space-y-6 overflow-y-auto h-[calc(100%-120px)]">
                    {activeTab === "shopcart" && (
                        <>
                            {cartItems.map((item) => (
                                <div key={item.id} className="flex items-start space-x-4">
                                    <img
                                        src={item.image}
                                        alt={item.name}
                                        className="w-16 h-16 object-cover border rounded"
                                    />
                                    <div className="flex-1">
                                        <p className="text-sm font-medium">{item.name}</p>
                                        <p className="text-xs text-gray-500">
                                            In stock: {item.stock}
                                        </p>
                                        <div className="flex items-center mt-2 space-x-2">
                                            <button className="p-1 border rounded">
                                                <Minus size={14} />
                                            </button>
                                            <span>{item.qty}</span>
                                            <button className="p-1 border rounded">
                                                <Plus size={14} />
                                            </button>
                                            <span className="ml-auto font-semibold">
                                                ${item.price.toFixed(2)}
                                            </span>
                                        </div>
                                        <button className="text-red-500 text-xs flex items-center mt-1">
                                            <Trash2 size={12} className="mr-1" /> Remove
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </>
                    )}

                    {activeTab === "order" && (
                        <div className="text-gray-500 text-sm">
                            📦 Your order history will appear here...
                        </div>
                    )}
                </div>

                {activeTab === "shopcart" && (
                    <div className="p-6 border-t">
                        <button className="w-full bg-green-600 text-white py-2 rounded-lg">
                            💳 Payment
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
}
